local Loader            = { Loaded = false }

Loader["Execute"] = function()
    local _Success, _Error = pcall(mn)

    if _Success then
        Library:Notify({
            Title       = "Loader",
            Description = "Script executed successfully wait 1-5 seconds!",
            Time        = 5
        });
    else
        Library:Notify({
            Title       = "Loader Error",
            Description = "Error: " .. tostring(_Error),
            Time        = 10
        });
    end

    task.delay(11, function()
        Library:Unload();
    end);
end

Loader.Execute();
